ALTER TABLE `sports_entertainment_ecm`.`legal`.`ip_portfolio` ADD CONSTRAINT `fk_legal_ip_portfolio_corporate_entity_id` FOREIGN KEY (`corporate_entity_id`) REFERENCES `sports_entertainment_ecm`.`legal`.`corporate_entity`(`corporate_entity_id`);
